import{_ as a,o as n,c as e,a as i}from"./chunks/framework.8tiMeCK-.js";const b=JSON.parse('{"title":"11.4  用 KGDB 狠狠地调试内核","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_debugging/ch11_4.md","filePath":"notes/linux_kernel_debugging/ch11_4.md","lastUpdated":null}'),p={name:"notes/linux_kernel_debugging/ch11_4.md"};function l(t,s,r,d,h,c){return n(),e("div",null,[...s[0]||(s[0]=[i(`<h1 id="_11-4-用-kgdb-狠狠地调试内核" tabindex="-1">11.4 用 KGDB 狠狠地调试内核 <a class="header-anchor" href="#_11-4-用-kgdb-狠狠地调试内核" aria-label="Permalink to &quot;11.4  用 KGDB 狠狠地调试内核&quot;">​</a></h1><p>上一节我们已经把这只名为「ARM VExpress」的虚拟羊养活了。它能在 QEMU 里欢快地跑起来，吐出一堆启动日志，最后乖乖地给你一个 shell 提示符。</p><p>但这还不够。</p><p>作为一个内核开发者，光是看着它跑起来是远远不够的——你得能把它按住，切开，看看它脑子里现在到底在想什么。这一节，我们要把这只有些飘忽的虚拟羊变成一个透明的玻璃标本，每一个函数调用、每一次指针跳转都要在我们的掌控之中。</p><p>这就引出了我们在这一章真正要讲的硬菜：<strong>KGDB</strong>。</p><hr><h3 id="唤醒野兽-让内核在启动时停下来" tabindex="-1">唤醒野兽：让内核在启动时停下来 <a class="header-anchor" href="#唤醒野兽-让内核在启动时停下来" aria-label="Permalink to &quot;唤醒野兽：让内核在启动时停下来&quot;">​</a></h3><p>现在的内核像是一列出站后就加速狂奔的火车，如果不采取点措施，它是不会主动停下来等你的。</p><p>我们现在的目标是：<strong>让内核在启动的最早期就暂停下来，像个听话的学生一样坐在那里等老师（GDB）来提问。</strong></p><p>如果你翻过内核文档，你会知道为了在真实硬件上做到这一点，通常需要两步走：</p><ol><li>编译内核时开启 KGDB 支持，并指定一个 I/O 驱动（比如 <code>kgdboc</code>），告诉内核：「用串口跟外界说话」。</li><li>在启动参数里加上 <code>kgdbwait</code>，告诉内核：「一启动就给我等着，别动」。</li></ol><p>但在 QEMU 的虚拟世界里，这一切可以简单得多——或者说，更「黑客」一点。QEMU 本身就是上帝视角，它不需要串口这种慢吞吞的物理介质，可以直接在内存里跟 GDB 打交道。</p><hr><h3 id="运行目标系统-给-qemu-上点手段" tabindex="-1">运行目标系统：给 QEMU 上点手段 <a class="header-anchor" href="#运行目标系统-给-qemu-上点手段" aria-label="Permalink to &quot;运行目标系统：给 QEMU 上点手段&quot;">​</a></h3><p>打开刚才跑 QEMU 的终端，我们需要给那条长长的命令加点佐料。</p><p>QEMU 提供了两个极其方便的参数（请务必记住它们，你会用得很频繁）：</p><ul><li><code>-S</code>：Freeze CPU at startup。冻结 CPU，不让它跑。相当于按下了暂停键。</li><li><code>-s</code>：Shorthand for <code>-gdb tcp::1234</code>。在 1234 端口上开一个监听，等着 GDB 连进来。</li></ul><p>好了，现在把你的 QEMU 启动命令修改一下。注意，我们在上一节的基础上增加了 <code>-S -s</code>，并且给内核传递了 <code>nokaslr</code> 参数——这一点至关重要，因为 KASLR（内核地址空间随机化）会让你的函数地址飘忽不定，调试起来就像在打移动靶，所以我们要先把它这层防御卸掉。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qemu-system-arm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 512</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -M</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vexpress-a9</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -smp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 4,sockets=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -kernel</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">..</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/seals_staging_vexpress/images/zImage</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -drive</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> file=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">..</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/seals_staging_vexpress/images/rfs.img,if=sd,format=raw</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -append</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;console=ttyAMA0 rootfstype=ext4 root=/dev/mmcblk0 init=/sbin/init nokaslr&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -nographic</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -no-reboot</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -audiodev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> id=none,driver=none</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -dtb</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">..</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/seals_staging_vexpress/images/vexpress-v2p-ca9.dtb</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -S</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>回车敲下去。</p><p>你会发现，这次没有滚动的 log，没有 <code>Freeing unused kernel memory</code>，屏幕一片死寂。</p><p>这就对了。这只羊已经被冻住了。</p><p>⚠️ <strong>注意</strong> 如果在你的机器上这一步有什么奇怪的行为，检查一下是不是后台已经跑着一个 QEMU 进程在占用资源。虽然纯软件模拟的 ARM（跑在 x86 上）通常不太会撞车，但总是保险一点好。</p><hr><h3 id="连接客户端-gdb-登场" tabindex="-1">连接客户端：GDB 登场 <a class="header-anchor" href="#连接客户端-gdb-登场" aria-label="Permalink to &quot;连接客户端：GDB 登场&quot;">​</a></h3><p>现在，舞台交给了宿主机上的 GDB。这里有一个极其容易混淆的点，我必须强调一下：</p><p><strong>我们要用的是交叉编译工具链里的 GDB，不是你系统里那个原生的 gdb！</strong></p><p>为什么？因为这是在跑 ARM 代码，你用 x86 的 GDB 去调试 ARM 的世界，那就是鸡同鸭讲。</p><p>开一个新的终端窗口（因为 QEMU 那个窗口已经被占用了），把调试器叫出来：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> arm-none-linux-gnueabihf-gdb</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -q</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">..</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/seals_staging_vexpress/linux-5.10.109/vmlinux</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Reading</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> symbols</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> from</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">..</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/seals_staging_vexpress/linux-5.10.109/vmlinux...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>看到那句 <code>Reading symbols</code> 了吗？这太重要了。</p><p>注意这里加载的是 <code>vmlinux</code>——那个<strong>未压缩</strong>的、胖胖的、带着满肚子调试符号的内核 ELF 文件，而不是我们刚才启动用的瘦子 <code>zImage</code>。GDB 现在正在把内核里所有的函数地址、变量结构统统吃到脑子里去。</p><p>一旦符号加载完毕，我们就有了这只羊的完整地图。现在，只需要把地图和实地连起来：</p><div class="language-gdb vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">gdb</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) target remote :1234</span></span>
<span class="line"><span>Remote debugging using :1234</span></span>
<span class="line"><span>0x60000000 in ?? ()</span></span>
<span class="line"><span>(gdb)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>那个 <code>0x60000000</code> 是什么？那是程序计数器（PC）停下的地方。虽然现在还没加载符号所以它显示 <code>??</code>，但这标志着连接成功了。</p><hr><h3 id="第一次断点-像魔法一样暂停" tabindex="-1">第一次断点：像魔法一样暂停 <a class="header-anchor" href="#第一次断点-像魔法一样暂停" aria-label="Permalink to &quot;第一次断点：像魔法一样暂停&quot;">​</a></h3><p>现在，你是上帝。</p><p>你可以让这只野兽继续跑，也可以让它随时停下。让我们试个最经典的：在网络驱动初始化的地方设个卡子。</p><div class="language-gdb vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">gdb</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) b register_netdev</span></span>
<span class="line"><span>Breakpoint 2 at 0x80754bc8: file net/core/dev.c, line 10238.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>输入 <code>c</code>（continue），让内核继续跑。</p><p>屏幕上开始滚动了。但没过多久，就像撞上了一堵看不见的墙——它停住了。GDB 跳了出来，告诉你断点触发了：</p><div class="language-gdb vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">gdb</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) c</span></span>
<span class="line"><span>Continuing.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Breakpoint 2, register_netdev (dev=0x818a0800) at net/core/dev.c:10238</span></span>
<span class="line"><span>10238    {</span></span>
<span class="line"><span>(gdb)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>这简直太爽了。</p><p>输入 <code>bt</code>（backtrace），你会看到一长串调用栈——从底层的汇编启动代码，一直到 C 语言的网络子系统，层层叠叠，清晰可见。</p><div class="language-gdb vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">gdb</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) bt</span></span>
<span class="line"><span>#0  register_netdev (dev=0x818a0800) at net/core/dev.c:10238</span></span>
<span class="line"><span>#1  0x8085b8a4 in smsc911x_probe (...) at drivers/net/ethernet/smsc/smsc911x.c:2466</span></span>
<span class="line"><span>#2  0x8047d1f8 in platform_drv_probe (...) at drivers/base/platform.c:645</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>(gdb)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>这就是 <code>register_netdev</code> 函数的现场。你现在就站在这个函数的门口，手里拿着手术刀。</p><hr><h3 id="实战演练-透视数据结构" tabindex="-1">实战演练：透视数据结构 <a class="header-anchor" href="#实战演练-透视数据结构" aria-label="Permalink to &quot;实战演练：透视数据结构&quot;">​</a></h3><p>既然停下来了，我们不妨做点更刺激的。</p><p><code>register_netdev</code> 的参数是一个 <code>struct net_device *</code> 指针。这个结构体是网络子系统的核心，大得离谱。让我们看看它长什么样：</p><div class="language-gdb vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">gdb</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) p dev</span></span>
<span class="line"><span>$1 = (struct net_device *) 0x818a0800</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>只是一个地址。不够劲。把内容全打出来：</p><div class="language-gdb vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">gdb</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) p *dev</span></span>
<span class="line"><span>$2 = {name = &quot;eth%d\\000...&quot;, name_node = 0x0, ifalias = 0x0, mem_end = 0, ...}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>如果你在终端里看到这一坨东西挤成一团，估计要头大。GDB 默认的输出格式确实有点反人类。</p><p>但我们可以调整它。输入这行命令，你的世界会清静很多：</p><div class="language-gdb vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">gdb</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) set print pretty</span></span>
<span class="line"><span>(gdb) p *dev</span></span>
<span class="line"><span>$3 = {</span></span>
<span class="line"><span>  name = &quot;eth%d\\000\\000\\000\\000\\000\\000\\000\\000\\000\\000&quot;,</span></span>
<span class="line"><span>  name_node = 0x0,</span></span>
<span class="line"><span>  ifalias = 0x0,</span></span>
<span class="line"><span>  mem_end = 0,</span></span>
<span class="line"><span>  mem_start = 0,</span></span>
<span class="line"><span>  base_addr = 0,</span></span>
<span class="line"><span>  irq = 30,</span></span>
<span class="line"><span>  state = 4,</span></span>
<span class="line"><span>  ...</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>(gdb)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><p>这就舒服多了。</p><p>你可以看到这个设备的 IRQ 号是 30，名字还是模板字符串 <code>eth%d</code>（因为还没注册完）。这就是内核在启动那一瞬间的真实面貌——没有任何秘密可言。</p><hr><h3 id="再次出发-让它跑完-再把它抓回来" tabindex="-1">再次出发：让它跑完，再把它抓回来 <a class="header-anchor" href="#再次出发-让它跑完-再把它抓回来" aria-label="Permalink to &quot;再次出发：让它跑完，再把它抓回来&quot;">​</a></h3><p>看完了现场，我们还得让系统活命。继续输入 <code>c</code>。</p><p>系统会完成剩下的启动流程，直到你再次看到那个熟悉的 <code>/ #</code> 提示符。</p><p>你以为调试结束了吗？不。</p><p>只要 QEMU 还在跑，只要 GDB 还连着，你随时可以把这只羊拽回来。在 GDB 的窗口里按下 <code>Ctrl + C</code>。</p><div class="language-gdb vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">gdb</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) c</span></span>
<span class="line"><span>Continuing.</span></span>
<span class="line"><span>^C</span></span>
<span class="line"><span>Program received signal SIGINT, Interrupt.</span></span>
<span class="line"><span>cpu_v7_do_idle () at arch/arm/mm/proc-v7.S:78</span></span>
<span class="line"><span>78      ret      lr</span></span>
<span class="line"><span>(gdb)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>看，它停在了 <code>cpu_v7_do_idle</code>。这是 ARM 处理器没事干的时候打盹的地方。</p><p>用 <code>bt</code> 看一眼栈，你会看到它确实是在 idle 进程里待着呢。</p><p>这就是源码级远程调试的威力。你不是在猜它为什么慢，你是在看着它干活。</p><hr><h3 id="收尾-像绅士一样关机" tabindex="-1">收尾：像绅士一样关机 <a class="header-anchor" href="#收尾-像绅士一样关机" aria-label="Permalink to &quot;收尾：像绅士一样关机&quot;">​</a></h3><p>玩够了，别像杀进程那样粗暴地干掉 QEMU。</p><p>虽然直接杀掉也行，但既然我们现在是在模拟一个正经的 Linux 系统，就尽量按规矩来。在那个串口终端里输入 <code>poweroff</code>，看着它优雅地关闭：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/ # poweroff</span></span>
<span class="line"><span>[    ... ] System halted.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>好了，这一章的“开膛手”课程只是个热身。我们学会了怎么把内核按住，但真正的挑战往往是那些你自己写的、一加载就炸的内核模块。</p><p>下一节，我们就来对付那些捣乱的模块。</p>`,76)])])}const k=a(p,[["render",l]]);export{b as __pageData,k as default};
